void employee_str(const Employee *e,char *out){sprintf(out,"Employee Name: %s, Salary: %d",e->name,e->salary);} 
void employee_repr(const Employee *e,char *out){sprintf(out,"Employee('%s', %d)",e->name,e->salary);} 
void student_show_info(const Student *s,char *out){sprintf(out,"Student Info: Name: %s | Marks: %d",s->name,s->marks);} 
void student_str(const Student *s,char *out){sprintf(out,"Student Name: %s, Marks: %d",s->name,s->marks);} 
