# COMPLETE, RUNNABLE Python3 code
import sys
class Employee:
    def __init__(self, name, salary):
        self.name = name
        self.salary = salary
    def show_info(self):
        return f"Employee Info: Name: {self.name} | Salary: {self.salary}"
    def __str__(self):
        return f"Employee Name: {self.name}, Salary: {self.salary}"
    def __repr__(self):
        return f"Employee('{self.name}', {self.salary})"
class Student:
    def __init__(self, name, marks):
        self.name = name
        self.marks = marks
    def show_info(self):
        return f"Student Info: Name: {self.name} | Marks: {self.marks}"
    def __str__(self):
        return f"Student Name: {self.name}, Marks: {self.marks}"
    def __repr__(self):
        return f"Student('{self.name}', {self.marks})"
def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it).strip())
    out = []
    for _ in range(T):
        emp_name = next(it).rstrip('\n')
        emp_salary = int(next(it).strip())
        stud_name = next(it).rstrip('\n')
        stud_marks = int(next(it).strip())
        emp = Employee(emp_name, emp_salary)
        stud = Student(stud_name, stud_marks)
        out.append(f"str(Employee): {str(emp)}")
        out.append(f"repr(Employee): {repr(emp)}")
        out.append(emp.show_info())
        out.append(f"str(Student): {str(stud)}")
        out.append(f"repr(Student): {repr(stud)}")
        out.append(stud.show_info())
    sys.stdout.write("\n".join(out))
if __name__ == "__main__":
    main()

